#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+5,M=2e5+5,K=105,INF=0x3f3f3f3f,Mod=1e9+7;
struct Gragh{int head[N],des[M],nxt[M],cnt;inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}}a;
int n,m,dp[N][K][2][2],siz[N],tmp[K][2][2];
void dfs(int u,int fa)
{
	dp[u][0][0][0]=dp[u][1][1][0]=siz[u]=1;grep(a,u,p)
	{
		int v=a.des[p];if(v==fa)continue;dfs(v,u);
		rep(0,min(siz[u],m),i)rep(0,1,j)rep(0,1,k)tmp[i][j][k]=dp[u][i][j][k],dp[u][i][j][k]=0;
		rep(0,min(m,siz[u]),i)rep(0,min(m-i,siz[v]),j)
		{
			dp[u][i+j][0][0]=(dp[u][i+j][0][0]+1ll*tmp[i][0][0]*dp[v][j][0][1]%Mod)%Mod;
			dp[u][i+j][1][0]=(dp[u][i+j][1][0]+1ll*tmp[i][1][0]*(dp[v][j][0][0]+dp[v][j][0][1])%Mod)%Mod;
			dp[u][i+j][0][1]=(dp[u][i+j][0][1]+1ll*tmp[i][0][0]*dp[v][j][1][1]%Mod+1ll*tmp[i][0][1]*(dp[v][j][1][1]+dp[v][j][0][1])%Mod)%Mod;
			dp[u][i+j][1][1]=(dp[u][i+j][1][1]+(1ll*tmp[i][1][0]*(dp[v][j][1][1]+dp[v][j][1][0])%Mod
				+1ll*tmp[i][1][1]*((dp[v][j][0][0]+dp[v][j][1][1])%Mod+(dp[v][j][1][0]+dp[v][j][0][1])%Mod)%Mod)%Mod)%Mod;
		}siz[u]+=siz[v];
	}
}
int main()
{
	n=read();m=read();rep(2,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	dfs(1,0);printf("%d",(dp[1][m][0][1]+dp[1][m][1][1])%Mod);
}
